#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int countComponents(int V, vector<vector<int>>& edges) {
        vector<int> parent(V);
        vector<int> rank(V, 0);
        for (int i = 0; i < V; i++) {
            parent[i] = i;
        }

        function<int(int)> find = [&](int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        };

        function<void(int, int)> union_ = [&](int x, int y) {
            int root_x = find(x), root_y = find(y);
            if (root_x != root_y) {
                if (rank[root_x] > rank[root_y]) {
                    parent[root_y] = root_x;
                } else if (rank[root_x] < rank[root_y]) {
                    parent[root_x] = root_y;
                } else {
                    parent[root_y] = root_x;
                    rank[root_x]++;
                }
            }
        };

        for (const auto& edge : edges) {
            union_(edge[0], edge[1]);
        }

        unordered_set<int> components;
        for (int i = 0; i < V; i++) {
            components.insert(find(i));
        }

        return components.size();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(2));
    for (int i = 0; i < E; i++) {
        cin >> edges[i][0] >> edges[i][1];
    }
    Solution sol;
    int ans = sol.countComponents(V, edges);
    cout << ans << '\n';
    return 0;
}
